{
  "context": {
    "networkId": "{{domain}}",
    "version": "{{version}}",
    "action": "catalog/publish",
    "bppId": "{{sellerplatform_id}}",
    "bppUri": "{{sellerplatform_host_root}}/bpp/receiver",
    "transactionId": "{{transaction_id}}",
    "messageId": "{{$guid}}",
    "timestamp": "{{iso_date}}",
    "schemaContext": [
      "https://schema.beckn.io/EnergyTradeOffer/v2.0/context.jsonld",
      "https://schema.beckn.io/EnergyResource/v2.0/context.jsonld",
      "https://schema.beckn.io/EnergyCustomer/v2.0/context.jsonld",
      "https://schema.beckn.io/DEGContract/v2.0/context.jsonld",
      "https://schema.beckn.io/BecknTimeSeries/v1.0/context.jsonld"
    ]
  },
  "message": {
    "catalogs": [
      {
        "id": "catalog-p2p-energy-2026-04",
        "descriptor": {
          "name": "Inter-Discom P2P Solar Energy",
          "shortDesc": "Rooftop solar energy from prosumers, traded across discoms"
        },
        "bppId": "sellerapp.example.com",
        "bppUri": "http://sellerapp.example.com/bpp/receiver",
        "provider": {
          "id": "TEST_SELLER_001",
          "descriptor": {
            "name": "Prosumer Solar Farm \u2014 North Delhi"
          }
        },
        "resources": [
          {
            "id": "energy-resource-solar-001",
            "descriptor": {
              "name": "Solar energy \u2014 2026-04-26 10:00\u201312:00 IST (2 hourly slots)",
              "shortDesc": "Up to 30 kWh @ 12 INR/kWh (slot 0) and 25 kWh @ 14 INR/kWh (slot 1)"
            },
            "resourceAttributes": {
              "@context": "https://schema.beckn.io/EnergyResource/v2.0/context.jsonld",
              "@type": "EnergyResource",
              "resourceType": "SOLAR",
              "resourceId": "TEST_METER_SELLER_001"
            }
          }
        ],
        "offers": [
          {
            "id": "offer-p2p-001",
            "descriptor": {
              "name": "Morning Solar \u2014 2 hourly slots from 10:00 IST",
              "shortDesc": "12 INR/kWh (slot 0) and 14 INR/kWh (slot 1)"
            },
            "resourceIds": ["energy-resource-solar-001"],
            "validity": {
              "startDate": "2026-04-25T06:00:00Z",
              "endDate": "2026-04-26T00:30:00Z"
            },
            "availableTo": [],
            "offerAttributes": {
              "@context": "https://schema.beckn.io/EnergyTradeOffer/v2.0/context.jsonld",
              "@type": "EnergyTradeOffer",
              "validityWindow": {
                "@type": "beckn:TimePeriod",
                "schema:startTime": "2026-04-25T06:00:00Z",
                "schema:endTime": "2026-04-26T00:30:00Z"
              },
              "contractTerms": {
                "@context": "https://schema.beckn.io/DEGContract/v2.0/context.jsonld",
                "@type": "DEGContract",
                "roles": [
                  {"role": "buyer", "participantId": "buyerapp.example.com"},
                  {"role": "seller", "participantId": "sellerapp.example.com"},
                  {"role": "buyerDiscom", "participantId": null},
                  {"role": "sellerDiscom", "participantId": "seller-discom-ledger.example.com"}
                ],
                "policy": {
                  "url": "https://raw.githubusercontent.com/beckn/DEG/refs/heads/main/specification/policies/p2p_trading_ies_wave2_revenue.rego",
                  "queryPath": "data.deg.contracts.p2p_trading"
                }
              },
              "inputs": [
                {
                  "role": "seller",
                  "participantId": "sellerapp.example.com",
                  "payload": {
                    "@context": "https://schema.beckn.io/BecknTimeSeries/v1.0/context.jsonld",
                    "@type": "TimeSeries",
                    "intervalPeriod": {
                      "start": "2026-04-26T04:30:00Z",
                      "duration": "PT1H"
                    },
                    "payloadDescriptors": [
                      {"objectType": "EVENT_PAYLOAD_DESCRIPTOR", "payloadType": "PRICE_PER_KWH", "currency": "INR"},
                      {"objectType": "EVENT_PAYLOAD_DESCRIPTOR", "payloadType": "AVAILABLE_QTY", "units": "KWH"}
                    ],
                    "intervals": [
                      {"id": 0, "payloads": [{"type": "PRICE_PER_KWH", "values": [12.5]}, {"type": "AVAILABLE_QTY", "values": [30.5]}]},
                      {"id": 1, "payloads": [{"type": "PRICE_PER_KWH", "values": [14.5]}, {"type": "AVAILABLE_QTY", "values": [25.5]}]}
                    ]
                  }
                },
                {
                  "role": "buyer",
                  "participantId": null,
                  "payloadDescriptors": [
                    {"objectType": "EVENT_PAYLOAD_DESCRIPTOR", "payloadType": "REQUESTED_QTY", "units": "KWH"}
                  ]
                },
                {
                  "role": "buyerDiscom",
                  "participantId": null,
                  "payloadDescriptors": [
                    {"objectType": "REPORT_PAYLOAD_DESCRIPTOR", "payloadType": "BUYER_DISCOM_ALLOC", "units": "KWH"},
                    {"objectType": "REPORT_PAYLOAD_DESCRIPTOR", "payloadType": "BUYER_DISCOM_STATUS", "units": "STRING"}
                  ]
                },
                {
                  "role": "sellerDiscom",
                  "participantId": "seller-discom-ledger.example.com",
                  "payloadDescriptors": [
                    {"objectType": "REPORT_PAYLOAD_DESCRIPTOR", "payloadType": "SELLER_DISCOM_ALLOC", "units": "KWH"},
                    {"objectType": "REPORT_PAYLOAD_DESCRIPTOR", "payloadType": "SELLER_DISCOM_STATUS", "units": "STRING"}
                  ]
                }
              ]
            },
            "provider": {
              "id": "TEST_SELLER_001",
              "descriptor": {
                "name": "Prosumer Solar Farm \u2014 North Delhi"
              },
              "providerAttributes": {
                "@context": "https://schema.beckn.io/EnergyCustomer/v2.0/context.jsonld",
                "@type": "EnergyCustomer",
                "meterId": "TEST_METER_SELLER_001",
                "utilityId": "TEST_DISCOM_SELLER",
                "utilityCustomerId": "TEST_CUST_SELLER_001"
              }
            }
          }
        ]
      }
    ]
  }
}
